const LETTERS = 'abcdefghijklmnopqrstuvwxyz'.split('');
const TOL = 38; // design units tolerance
const ROUND_SIZE = 5;

let session = { letters:[], idx:0, clicks:[], revealed:false, roundScores:[], totalPts:0 };
let W, H, SCALE, OX, OY;

const canvas = document.getElementById('glyph-canvas');
const ctx = canvas.getContext('2d');
const wrap = document.getElementById('canvas-wrap');

function du2px(x,y){ return {cx: OX+x*SCALE, cy: OY-y*SCALE}; }
function px2du(cx,cy){ return {x:(cx-OX)/SCALE, y:(OY-cy)/SCALE}; }

function setupCanvas() {
  const vw = window.innerWidth, vh = window.innerHeight;
  const topH = 48, botH = 60;
  const avail = vh - topH - botH - 16;
  const size = Math.min(vw * 0.94, avail, 900);
  canvas.width = size; canvas.height = size;
  wrap.style.width = size+'px'; wrap.style.height = size+'px';
  W = size; H = size;
  const pad = 24;
  SCALE = Math.min((W-pad*2)/780, (H-pad*2)/1000);
  OX = (W-780*SCALE)/2;
  OY = H/2 + 250*SCALE;
}

function initSession() {
  // Pick 5 random letters
  const shuffled = [...LETTERS].sort(()=>Math.random()-0.5);
  session = { letters: shuffled.slice(0,5), idx:0, clicks:[], revealed:false, roundScores:[], totalPts:0 };
  document.getElementById('score-screen').classList.remove('show');
  updateDots();
  updateLabel();
  setInstructions('Click to place extrema points, then press Done.');
  setBtn('check');
  draw();
}

function currentGlyph(){ return GLYPHS[session.letters[session.idx]]; }
function currentLetter(){ return session.letters[session.idx]; }

// ── Dots ──
function updateDots() {
  document.getElementById('step-counter').textContent = `${session.idx + 1} / ${session.letters.length}`;
}

function updateLabel() {
  document.getElementById('letter-label').textContent = currentLetter();
}

function setInstructions(txt) {
  document.getElementById('instructions').textContent = txt;
}

function setBtn(state) {
  const btn = document.getElementById('action-btn');
  if (state==='check') { btn.textContent='Done'; btn.className='action-btn check'; }
  else if (state==='next') { btn.textContent='Next →'; btn.className='action-btn next'; }
  else if (state==='finish') { btn.textContent='See Score'; btn.className='action-btn finish'; }
}

// ── Draw ──
function draw() {
  ctx.clearRect(0,0,W,H);
  drawGuides();
  drawPath(currentGlyph().segments);
  if (session.revealed) drawReveal();
  else drawClicks();
}

function drawGuides() {
  const bl=du2px(0,0), xh=du2px(0,445), ch=du2px(0,750);
  ctx.save();
  [[bl.cy,'rgba(255,255,255,0.09)','baseline'],[xh.cy,'rgba(255,255,255,0.04)','x-height'],[ch.cy,'rgba(255,255,255,0.03)','cap']].forEach(([y,col,lbl])=>{
    ctx.strokeStyle=col; ctx.lineWidth=1; ctx.setLineDash([3,6]);
    ctx.beginPath(); ctx.moveTo(0,y); ctx.lineTo(W,y); ctx.stroke();
    ctx.setLineDash([]);
    ctx.fillStyle=col; ctx.font='9px IBM Plex Mono,monospace';
    ctx.fillText(lbl, 8, y-4);
  });
  ctx.restore();
}

function drawPath(segments) {
  ctx.save();
  ctx.beginPath();
  let first=true;
  for(const s of segments){
    if(s.type==='M'){if(!first)ctx.closePath();first=false;const p=du2px(s.x,s.y);ctx.moveTo(p.cx,p.cy);}
    else if(s.type==='L'){const p=du2px(s.x,s.y);ctx.lineTo(p.cx,p.cy);}
    else if(s.type==='C'){const p1=du2px(s.x1,s.y1),p2=du2px(s.x2,s.y2),p=du2px(s.x,s.y);ctx.bezierCurveTo(p1.cx,p1.cy,p2.cx,p2.cy,p.cx,p.cy);}
    else if(s.type==='Z')ctx.closePath();
  }
  ctx.closePath();
  ctx.fillStyle='rgba(232,228,220,0.07)';
  ctx.fill('evenodd');
  ctx.strokeStyle='rgba(232,228,220,0.92)';
  ctx.lineWidth=1.8; ctx.lineJoin='round'; ctx.stroke();
  ctx.restore();
}

function drawClicks() {
  session.clicks.forEach(c => {
    const {cx,cy}=du2px(c.x,c.y);
    ctx.save();
    ctx.beginPath(); ctx.arc(cx,cy,4,0,Math.PI*2);
    ctx.fillStyle='rgba(255,92,58,0.9)'; ctx.fill();
    ctx.restore();
  });
}

function drawReveal() {
  const g = currentGlyph();
  const targets = g.extrema;
  const matched = session.matchedTargets || new Set();

  // on-curve points — small hollow diamonds
  g.oncurve.forEach(p => {
    const {cx,cy}=du2px(p.x,p.y);
    ctx.save();
    ctx.translate(cx,cy); ctx.rotate(Math.PI/4);
    ctx.strokeStyle='rgba(91,156,246,0.5)'; ctx.lineWidth=1;
    ctx.strokeRect(-3.5,-3.5,7,7);
    ctx.restore();
  });

  // extrema targets — plain dots only
  targets.forEach((t,ti) => {
    const {cx,cy}=du2px(t.x,t.y);
    const isMatched = matched.has(ti);
    ctx.save();
    ctx.beginPath(); ctx.arc(cx,cy,5,0,Math.PI*2);
    ctx.fillStyle = isMatched ? 'rgba(62,201,122,0.9)' : 'rgba(255,92,58,0.9)';
    ctx.fill();
    ctx.restore();
  });

  // user clicks — plain dots
  session.clicks.forEach(c => {
    const {cx,cy}=du2px(c.x,c.y);
    const isHit = c.matchIdx !== undefined;
    ctx.save();
    ctx.beginPath(); ctx.arc(cx,cy,3.5,0,Math.PI*2);
    ctx.fillStyle = isHit ? 'rgba(62,201,122,0.6)' : 'rgba(255,92,58,0.35)';
    ctx.fill();
    ctx.restore();
  });
}

// ── Click handler ──
canvas.addEventListener('mousemove', e => {
  if(session.revealed) return;
  const r=canvas.getBoundingClientRect();
  const du=px2du(e.clientX-r.left, e.clientY-r.top);
  document.getElementById('coord-readout').textContent=`${Math.round(du.x)}, ${Math.round(du.y)}`;
});
canvas.addEventListener('mouseleave',()=>{ document.getElementById('coord-readout').textContent=''; });

canvas.addEventListener('click', e => {
  if(session.revealed) return;
  const r=canvas.getBoundingClientRect();
  const du=px2du(e.clientX-r.left, e.clientY-r.top);
  session.clicks.push({x:du.x, y:du.y});
  setInstructions(`${session.clicks.length} point${session.clicks.length!==1?'s':''} placed — press Done when ready.`);
  draw();
});


// ── Score logic ──
function scoreClicks() {
  const targets = currentGlyph().extrema;
  const usedClicks = new Set();
  const matched = new Set();

  targets.forEach((t,ti) => {
    let bestDist=TOL+1, bestCi=-1;
    session.clicks.forEach((c,ci) => {
      if(usedClicks.has(ci)) return;
      const d=Math.hypot(c.x-t.x, c.y-t.y);
      if(d<=TOL && d<bestDist){ bestDist=d; bestCi=ci; }
    });
    if(bestCi>=0){
      session.clicks[bestCi].matchIdx=ti;
      session.clicks[bestCi].dist=Math.round(bestDist);
      usedClicks.add(bestCi);
      matched.add(ti);
    }
  });

  session.matchedTargets = matched;
  const pts = Math.round((matched.size / targets.length) * 100);
  session.roundScores.push({ letter: currentLetter(), pts, found: matched.size, total: targets.length });
  session.totalPts += pts;
  return pts;
}

// ── Action button ──
document.getElementById('action-btn').addEventListener('click', () => {
  const btn = document.getElementById('action-btn');
  if(btn.className.includes('check')) {
    // Reveal
    scoreClicks();
    session.revealed = true;
    draw();
    const last = session.roundScores[session.roundScores.length-1];
    setInstructions(`${last.found}/${last.total} extrema found.`);
    const isLast = session.idx === session.letters.length - 1;
    setBtn(isLast ? 'finish' : 'next');
  } else if(btn.className.includes('next')) {
    session.idx++;
    session.clicks = [];
    session.revealed = false;
    session.matchedTargets = null;
    updateDots();
    updateLabel();
    setInstructions('Click to place extrema points, then press Done.');
    setBtn('check');
    draw();
  } else if(btn.className.includes('finish')) {
    showScore();
  }
});

function showScore() {
  const screen = document.getElementById('score-screen');
  screen.classList.add('show');
  
  const avg = Math.round(session.totalPts / ROUND_SIZE);
  document.getElementById('sc-big-num').textContent = avg;
  document.getElementById('sc-sub-text').textContent = avg===100?'Perfect!': avg>=80?'Excellent':avg>=60?'Good work':'Keep practicing';

  const bd = document.getElementById('sc-breakdown');
  bd.innerHTML = '';
  session.roundScores.forEach(r => {
    const row = document.createElement('div');
    row.className = 'sc-row';
    const pct = r.pts;
    row.innerHTML = `
      <span class="sc-char">${r.letter}</span>
      <div class="sc-bar-wrap"><div class="sc-bar" style="width:0%;background:${pct>=80?'var(--green)':pct>=50?'var(--accent2)':'var(--accent)'}"></div></div>
      <span class="sc-pts">${r.found}/${r.total}</span>
    `;
    bd.appendChild(row);
    setTimeout(()=>{ row.querySelector('.sc-bar').style.width=pct+'%'; }, 80);
  });
}

document.getElementById('sc-restart-btn').addEventListener('click', initSession);

setupCanvas();
initSession();
window.addEventListener('resize', () => { setupCanvas(); draw(); });
